INSERT INTO public.photos VALUES (22041, 'Plaza del Justicia 1951', 'La plaza del Justicia, un recoleto espacio abierto junto a la calle de la Manifestaciâ”śâ”‚n, en una imagen con su isleta central de jardines, â”śĂ­rboles y bancos que la caracterizaba desde unas dâ”śÂ®cadas antes. A la derecha, la antigua casa de los Sobradiel y de los Gabarda, hasta que en los aâ”śâ–’os 30 fue habilitada como sede del Ilustre Colegio Notarial de Aragâ”śâ”‚n. Al fondo, la fachada barroca de la iglesia de Santa Isabel o de San Cayetano, denominaciâ”śâ”‚n popular esta â”śâ•‘ltima que tambiâ”śÂ®n es comâ”śâ•‘n para identificar este espacio. En 1962 fue instalada aquâ”śÂˇ la fuente de La Samaritana, procedente de la plaza de La Seo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65602400, -0.88153600, '0101000020E61000009BE447FC8A35ECBF10B22C98F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14741052938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14741052938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14741052938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22180, 'Pl. de Lanuza 1954', 'Hospederâ”śÂˇa Carroll y San Jorge situada en la plaza de Lanuza nâ”¬â•‘ 27, en la manzana de edificios adosados a la antigua muralla de piedra y frente a la puerta norte del Mercado Central. Un recordatorio de las numerosas posadas y mesones que estuvieron localizados en el entorno de la antigua plaza del Mercado. Aâ”śâ–’os despuâ”śÂ®s, esta manzana serâ”śÂˇa derribada. Fuente visual: Revista Aragâ”śâ”‚n, abril, mayo y junio de 1954.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65673400, -0.88239500, '0101000020E6100000EAEC6470943CECBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31797596720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31797596720.webp', 'https://www.flickr.com/photos/zaragozaantigua/31797596720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22264, 'Plaza del Justicia 1967', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 24/03/1967. Extraordinaria y aguerrida columna de recios y pavorosos legionarios romanos, pasando por el trance de la figuraciâ”śâ”‚n durante la conmemoraciâ”śâ”‚n anual cristiana de la Pasiâ”śâ”‚n, Muerte y Resurrecciâ”śâ”‚n del nazareno Jesâ”śâ•‘s. La imagen recoge el ardoroso despliegue guerrero en la Plaza del Justicia. Al fondo, la iglesia de Santa Isabel, o San Cayetano. Esta "Guardia Pretoriana" estaba formada por un centuriâ”śâ”‚n y varios soldados, ademâ”śĂ­s de tambor y clarâ”śÂˇn, y acompaâ”śâ–’aba al paso de "Jesâ”śâ•‘s camino del Calvario" ("Jesus walked to Calvary").', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65622400, -0.88159900, '0101000020E610000034F6251B0F36ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14825797250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14825797250.webp', 'https://www.flickr.com/photos/zaragozaantigua/14825797250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22280, 'Murallas Romanas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 2/2/66. Basamento y columnas del Augusto de Prima Porta, exhibido junto al torreâ”śâ”‚n de la Zuda (derecha) entre 1950 y 1966 y retirado antes de hacer la foto. Antes y despuâ”śÂ®s estuvo en distintas ubicaciones de la ciudad; hoy se puede ver muy cerca. En el pedestal se lee: "Aquâ”śÂˇ el aâ”śâ–’o XXIII a. de J.C. las legiones IIII Macedâ”śâ”‚nica, VI Victrix y X Gâ”śÂ®mina fundaron la Colonia Caesaraugusta". Mâ”śĂ­s informaciâ”śâ”‚n: jorge-entrecomillas.blogspot.com.es/2012/05/la-estatua-de...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65701000, -0.88182200, '0101000020E610000003965CC5E237ECBF8E9257E718D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15003904019.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15003904019.webp', 'https://www.flickr.com/photos/zaragozaantigua/15003904019/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22361, 'Pl. de Lanuza c.1968', 'Foto: Jesâ”śâ•‘s Domeque. Aspecto del derribo de la manzana de casas que perduraba en la actual ubicaciâ”śâ”‚n de la estatua de Câ”śÂ®sar Augusto, frente a la puerta norte del Mercado Central. Al fondo de la calle Murallas Romanas, iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=10204804368382012&set...', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21035754534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21035754534.webp', 'https://www.flickr.com/photos/zaragozaantigua/21035754534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22428, 'Calle de las Murallas 1965', 'Colorista imagen capturada en la calle de las Murallas, entre la calle de la Manifestaciâ”śâ”‚n y la plaza de Câ”śÂ®sar Augusto, centrada en un tramo de las antiguas murallas de piedra de la ciudad y el torreâ”śâ”‚n de la Zuda. A la derecha, vista parcial de la iglesia de San Juan de los Panetes. Fuente visual: Lala Aufsberg, Bildarchiv Foto Marburg.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65707100, -0.88185800, '0101000020E610000036E9B6442E38ECBF34130CE71AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27988842839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27988842839.webp', 'https://www.flickr.com/photos/zaragozaantigua/27988842839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22463, 'Mercado Central 1968', 'Desfile de la Hermandad Provincial de Caballeros Legionarios de Zaragoza que, desde la calle de Manifestaciâ”śâ”‚n (al fondo), estâ”śĂ­ llegando a paso ligero a la altura del Mercado Central, flanqueada por nutrida parroquia que contiene el aliento ante esta necrofâ”śÂˇlica demostraciâ”śâ”‚n. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65673400, -0.88239500, '0101000020E6100000EAEC6470943CECBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32587924561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32587924561.webp', 'https://www.flickr.com/photos/zaragozaantigua/32587924561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22466, 'Pl. del Justicia 1967', 'Imagen de las traseras del simplificado "Paso de la Caâ”śÂˇda del Seâ”śâ–’or", conducido por la "Cofradâ”śÂˇa de Jesâ”śâ•‘s Camino del Calvario", durante la nocturna Procesiâ”śâ”‚n de las Tres Caâ”śÂˇdas. Acompaâ”śâ–’ando al paso, tremendista procesionaria de descalzos penitentes cargando madero y arrastrando cadenas, y penitentas expiando culpas. La captura se ha realizado en la plaza del Justicia, con el fondo edilicio de la calle Manifestaciâ”śâ”‚n. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65619700, -0.88135400, '0101000020E6100000705CC64D0D34ECBFDD5D6743FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32902408685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32902408685.webp', 'https://www.flickr.com/photos/zaragozaantigua/32902408685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22555, 'Vista parcial 1970', 'Desde el excelente mirador de la torre de San Francisco de Borja del Pilar, con el marco de uno de sus vanos, y en una tarde de frâ”śÂˇo y niebla, vista orientada al oeste. Al fondo, la torre de San Pablo. A la izquierda, las dos torres de la iglesia de Santa Isabel y el Mercado Central. Mâ”śĂ­s inmediata, la plaza del Pilar, con el Altar de la Patria. Despuâ”śÂ®s, la plaza de Câ”śÂ®sar Augusto, las murallas romanas y la iglesia de San Juan de los Panetes.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65696300, -0.88034100, '0101000020E6100000747E8AE3C02BECBF4DD7135D17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15065655424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15065655424.webp', 'https://www.flickr.com/photos/zaragozaantigua/15065655424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22566, 'Mercado Central 1973', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Octubre 1973. Otro de los comercios veteranos con aires mâ”śĂ­s de la antigua plaza del Mercado, que del Mercado Central. Sogas, cuerdas, cestas, derivados textiles naturales cuando el boom del momento era el plâ”śĂ­stico, el polyester, el papel pintado de diseâ”śâ–’os romboidales. La imagen estâ”śĂ­ tomada en el pedacito de Câ”śÂ®sar Augusto entre Casta â”śĂĽlvarez (hacia la derecha) y Predicadores (a la espalda). El Mercado Central queda, fuera de plano, inmediato a la izquierda.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65670500, -0.88264300, '0101000020E6100000F16261889C3EECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15232287261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15232287261.webp', 'https://www.flickr.com/photos/zaragozaantigua/15232287261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22567, 'Mercado Central 1974', 'El Mercado Central no encajaba con el Plan Parcial de la Vâ”śÂˇa Imperial de 1973. Al incluir su derribo, marcâ”śâ”‚ el inicio de la campaâ”śâ–’a Salvemos al mercado que recogiâ”śâ”‚ mâ”śĂ­s de 30.000 firmas y el apoyo de entidades y personalidades de la ciudad. En 1978, un Real Decreto declarâ”śâ”‚ monumento histâ”śâ”‚rico-artâ”śÂˇstico de carâ”śĂ­cter nacional el edificio del mercado de Lanuza. En la imagen, chavalerâ”śÂˇa dâ”śĂ­ndole a la pelota frente al ingreso norte del Mercado Lanuza.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65684100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15234006727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15234006727.webp', 'https://www.flickr.com/photos/zaragozaantigua/15234006727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
