INSERT INTO public.photos VALUES (22877, 'Vista desde iglesia Sta. Isabel 1987', 'Luis Mâ”śÂˇnguez. 1987. Desde la torre de la iglesia de Santa Isabel de Portugal mâ”śĂ­s cercana a la calle del Buen Pastor, una mirada perspectiva hacia el Norte, que nos conduce a las Murallas Romanas, el Torreâ”śâ”‚n de la Zuda, el puente de Santiago, la avenida de los Pirineos, el parque del Tâ”śÂˇo Jorge a la derecha, los bloques de vivienda de la margen izquierda, hasta los montes de Juslibol.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65593600, -0.88208100, '0101000020E61000000589EDEE013AECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15851644101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15851644101.webp', 'https://www.flickr.com/photos/zaragozaantigua/15851644101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22905, 'Av. Câ”śÂ®sar Augusto 1989', 'Porches junto al Mercado Central, en la avenida Câ”śÂ®sar Augusto, tramo comprendido entre las calles del Buen Pastor y del Olmo, el 14 de febrero de 1989. Las columnas forjadas en Averly son parte de un proyecto inacabado de Ricardo Magdalena, que pretendâ”śÂˇa que rodeasen todo el mercado. Fuente: "Memoria de las calles de Zaragoza", Juliâ”śĂ­n Ruiz Marâ”śÂˇn, Librerâ”śÂˇa General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65607900, -0.88276900, '0101000020E610000023861DC6A43FECBFD34B8C65FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21784624740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21784624740.webp', 'https://www.flickr.com/photos/zaragozaantigua/21784624740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22931, 'Calle de Prudencio 1987', 'Imagen capturada desde cierta altura en las traseras de los Juzgados de la plaza del Pilar, con el panorama previo a la ampliaciâ”śâ”‚n realizada entre 1991 y 1993 con proyecto de Alejandro de la Sota Martâ”śÂˇnez y Juan Capella Callis. El montaje fotogrâ”śĂ­fico de la â”śÂ®poca abarca desde la calle de los Convertidos, a la izquierda, pasando por la de Prudencio, al frente, y llega hasta la calle de la Virgen y de las Danzas, a la derecha. Tras la finalizaciâ”śâ”‚n del derribo de los nâ”śâ•‘meros impares de la antigua calle de las Danzas, el espacio resultante devino en otro gran aparcamiento en superficie que durâ”śâ”‚ hasta el inicio de las obras. Fuente visual: www.alejandrodelasota.org/', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65638700, -0.88028900, '0101000020E6100000D5E940D6532BECBF81423D7D04D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31271465793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31271465793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31271465793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22967, 'Calle Manifestaciâ”śâ”‚n 1994', '1994. Derribo de edificios de la calle Manifestaciâ”śâ”‚n angular con la Plaza del Justicia.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65637600, -0.88184500, '0101000020E61000000E8464011338ECBF8DF0F62004D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14944756779.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14944756779.webp', 'https://www.flickr.com/photos/zaragozaantigua/14944756779/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22976, 'Av. Câ”śÂ®sar Augusto 1994', '1994. Demoliciâ”śâ”‚n completa de varios edificios de viviendas, entre medianiles, en la esquina de la Avenida Câ”śÂ®sar Augusto con la calle Casta â”śĂĽlvarez.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65670500, -0.88264300, '0101000020E6100000F16261889C3EECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15131027002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15131027002.webp', 'https://www.flickr.com/photos/zaragozaantigua/15131027002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23048, 'Calle de los Predicadores 1991', 'Imagen capturada durante la oficial inauguraciâ”śâ”‚n de la calle de los Predicadores tras las obras de reforma integral, durante las cuales se renovaron los servicios y el pavimento de este vial. En esta calle tambiâ”śÂ®n, signo de los tiempos, se recuperâ”śâ”‚ para el firme carretero un moderno adoquinado de piedra que con el tiempo fue dando problemas de mantenimiento solventados con econâ”śâ”‚micos parches de asfalto. En la imagen, capturada en el arranque de la calle desde la avenida de Câ”śÂ®sar Augusto, ceremonia oficial de inauguraciâ”śâ”‚n de la reformada calle con el preceptivo corte de cinta por el alcalde Antonio Gonzâ”śĂ­lez Triviâ”śâ–’o, aquâ”śÂˇ acompaâ”śâ–’ado por su "nâ”śâ•‘mero 2", el Primer Teniente de Alcalde y concejal de Urbanismo, Luis Garcâ”śÂˇa Nieto. En segundo tâ”śÂ®rmino, el Mercado Central Lanuza.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65682500, -0.88265000, '0101000020E6100000910F7A36AB3EECBFFC1873D712D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437637038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437637038.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437637038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23148, 'Plaza del Pilar 2009', 'Viâ”śâ–’eta de la historieta "La gran invasiâ”śâ”‚n", de Alfonso Pinedo, incluida en el volumen de câ”śâ”‚mic "Hotel Safari", editado en Zaragoza en 2009. Se puede observar una batalla en la que estâ”śĂ­n presentes un ejâ”śÂ®rcito de zombies nazis, guerreros ninja, robots mutantes soviâ”śÂ®ticos, gorilas gigantes, etc. Al fondo, la basâ”śÂˇlica del Pilar, en el momento de perder la torre de San Francisco de Borja. Fuente: Heraldo de Aragâ”śâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65684300, -0.88006900, '0101000020E61000004A26A7768629ECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32165857534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32165857534.webp', 'https://www.flickr.com/photos/zaragozaantigua/32165857534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23187, 'Manuel Ureâ”śâ–’a 2010', 'Foto Primo Romero, 2010. Viernes Santo, 2 de abril de 2010. El arzobispo de Zaragoza, Manuel Ureâ”śâ–’a, que habâ”śÂˇa sustituido en 2005 a Elâ”śÂˇas Yanes, se asoma a un balcâ”śâ”‚n del Colegio de Notarios, en la plaza del Justicia de Zaragoza, durante los actos de la Semana Santa. A su lado, sin motivo aparente, el alcalde de la ciudad (2003-2015), Juan Alberto Belloch. Ureâ”śâ–’a fue cesado en noviembre de 2014 por encubrir abusos sexuales. Belloch habâ”śÂˇa anunciado en septiembre que no se volverâ”śÂˇa a presentar a las elecciones municipales de 2015. Fuente: www.mhuel.org/paginas/noticias.htm', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65606900, -0.88181700, '0101000020E610000091D10149D837ECBFB075A911FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15346156732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15346156732.webp', 'https://www.flickr.com/photos/zaragozaantigua/15346156732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23788, 'Nevada plaza del Pilar 1967', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/invierno 1967. Despuâ”śÂ®s de que la antigua plaza del Pilar se tragara a sus colindantes de la antigua plaza de La Seo, y de la antigua plaza de Huesca, los dâ”śÂˇas de nieve y borrasca este era el mayor receptâ”śĂ­culo de cristales de hielo de toda la antigua ciudad romana. Y la chavalerâ”śÂˇa lo sabâ”śÂˇa. Nada que ver con esos lejanos dâ”śÂˇas de ferragosto, con sol martilleante, delirante.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65705800, -0.88048300, '0101000020E610000011E335AFEA2CECBF9FC9FE791AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664877380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664877380.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664877380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23798, 'La Cruz y sus Caâ”śÂˇdos 1954', 'Ayuntamiento de Zaragoza/Marâ”śÂˇn Chivite. (SF). Un decreto del general Franco de 16/XI/1938 proclamaba dâ”śÂˇa de luto nacional el 20 de noviembre de cada aâ”śâ–’o, en memoria de Josâ”śÂ® Antonio Primo de Rivera, y establecâ”śÂˇa, "previo acuerdo con las autoridades eclesiâ”śĂ­sticas, que en los muros de cada parroquia figure una inscripciâ”śâ”‚n que contenga los nombres de sus Caâ”śÂˇdos, ya en la presente Cruzada, ya vâ”śÂˇctimas de la revoluciâ”śâ”‚n marxista." Ese fue el origen de la colocaciâ”śâ”‚n de placas en las iglesias y de la construcciâ”śâ”‚n de monumentos conmemorativos "a los caâ”śÂˇdos". Despuâ”śÂ®s de abril de 1939, Espaâ”śâ–’a se llenâ”śâ”‚ de memoria de los vencedores. En Zaragoza, 1941, el alcalde Francisco Caballero propuso eternizar el recuerdo "de nuestros mejores", y un aâ”śâ–’o despuâ”śÂ®s la Corporaciâ”śâ”‚n Municipal convocâ”śâ”‚ un concurso para realizar un monumento funerario. Tras varios proyectos inviables, el monumento, rematado por una gran cruz, se colocâ”śâ”‚ en la Plaza del Pilar en 1954, dedicado "A los hâ”śÂ®roes y mâ”śĂ­rtires de Zaragoza. Caâ”śÂˇdos en la Cruzada de Liberaciâ”śâ”‚n 1936-1939." Allâ”śÂˇ, cada 20 de noviembre, hasta el final de la Dictadura, se celebraba un acto de homenaje en el que participaban las principales autoridades militares, religiosas, y civiles. En 1990, con motivo de la remodelaciâ”śâ”‚n de la Plaza del Pilar, la Gerencia de Urbanismo del Ayuntamiento de Zaragoza lo trasladâ”śâ”‚ al Cementerio de Torrero y puso, en su lugar, la actual "Fuente de la Hispanidad".', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65714600, -0.88078900, '0101000020E610000040A6B5696C2FECBF3E59315C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14915587645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14915587645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14915587645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23841, 'Plaza del Pilar 1967', 'La gran innovaciâ”śâ”‚n en la designaciâ”śâ”‚n de "procuradores" para la IXâ”¬Â¬ Legislatura de las franquistas Cortes Espaâ”śâ–’olas, fue la posibilidad de presentar candidatos por el tercio de masculinos cabezas de familia, y elegir entre ellos, o abstenerse. En la pugna para los dos puestos de la provincia de Zaragoza se presentaron ocho aspirantes. Uno de ellos era Faustino Ferrer Lledâ”śâ”‚, natural de Fuentes de Ebro, antiguo alfâ”śÂ®rez provisional metido a exitoso empresario en "Abad Metales", que tras pasar por la presidencia del Real Zaragoza (1958-62), y la vicepresidencia de la DPZ, se postulâ”śâ”‚ a Cortes Generales. Con el perturbador lema "Pienso en vuestras familias porque pienso en la mâ”śÂˇa", publicitâ”śâ”‚ su candidatura sin muchas posibilidades, porque los vencedores fueron los previstos: el ex-alcalde Luis Gâ”śâ”‚mez Laguna, y el radiofâ”śâ”‚nico "vigâ”śÂˇa de la Torre Nueva", Josâ”śÂ® Marâ”śÂˇa Zaldâ”śÂˇvar. A Faustino Ferrer le tocarâ”śÂˇa ser procurador en la siguiente Xâ”¬Â¬ Legislatura, que se alargarâ”śÂˇa hasta 1977 por cierto suceso imprevisto acaecido el 20-N de 1975. En la imagen, exposiciâ”śâ”‚n del Censo Electoral en la fachada del Convento de las Hijas de la Caridad de Santa Ana, en la plaza del Pilar, durante las elecciones de 1967 a procuradores por el tercio de las cabezas nucleares de familia. Fuente: Gerardo Sancho Ramo (Archivo Pâ”śâ•‘blico Municipal).', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65689100, -0.88080400, '0101000020E610000095F3C5DE8B2FECBFB404190115D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23679627739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23679627739.webp', 'https://www.flickr.com/photos/zaragozaantigua/23679627739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23842, 'Plaza del Pilar c.1941', 'Obras de remodelaciâ”śâ”‚n de la plaza del Pilar. Al fondo, la Zuda y San Juan de los Panetes. Fuente: Agencia EFE.', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24243646029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24243646029.webp', 'https://www.flickr.com/photos/zaragozaantigua/24243646029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23871, 'El Pilar 1942', 'Imagen parcial de la nueva gran plaza del Pilar desde el entorno de la desaparecida plaza de Huesca. A la izquierda, el provisional solar entre el templo y la recientemente terminada Hospederâ”śÂˇa del Pilar (fuera de plano), donde estaba previsto construir la nueva Casa de Infantes, y viviendas del Cabildo metropolitano. A la derecha, los â”śĂ­rboles de la antigua plaza del Pilar. En el centro, la genuina primera torre, denominada de Santiago.comenzada en 1715, y terminada en 1892. Fuente visual: www.todocoleccion.net/', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65683300, -0.87974300, '0101000020E61000005551BCCADA26ECBF7FF78E1A13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30861079202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30861079202.webp', 'https://www.flickr.com/photos/zaragozaantigua/30861079202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23885, 'Pl. del Pilar 1954', 'Imagen capturada, posiblemente desde la altura del reciente convento de las Hijas de la Caridad de Santa Ana, con interesante vista de la plaza del Pilar, destacando el inmediato gran solar entre la plaza y la calle de las Danzas, reservado para la construcciâ”śâ”‚n del gran edificio de los juzgados. A la derecha, el antiguo emboque a la calle de los Convertidos. Fuente visual: postal de Garcâ”śÂˇa Garrabella, en www.todocoleccion.net/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65657100, -0.88012800, '0101000020E610000088670932022AECBF4240BE840AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31704671480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31704671480.webp', 'https://www.flickr.com/photos/zaragozaantigua/31704671480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23905, 'Plaza del Pilar 1990', 'Imagen capturada durante las obras de rehabilitaciâ”śâ”‚n y embellecimiento de la plaza del Pilar que entre 1990 (tras las Fiestas del Pilar) y 1991 (antes de las elecciones municipales de finales del mes de mayo) transformaron la denominada "plaza de las Catedrales" en el postmoderno "salâ”śâ”‚n de la ciudad". En esta fotografâ”śÂˇa, maquinaria de obra extrae â”śĂ­ridos en el subsuelo delimitado entre la Hospederâ”śÂˇa del Pilar (izquierda) y los Juzgados (derecha) al objeto de permitir luego la construcciâ”śâ”‚n del homâ”śâ”‚nimo aparcamiento. Detrâ”śĂ­s, los accesos al Pilar permanecen siempre despejados en el tramo de la plaza que fuera el original tamaâ”śâ–’o de la misma. Al fondo, pluma de obra en la plaza de la Seo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87993500, '0101000020E61000006362F3716D28ECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50457850423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50457850423.webp', 'https://www.flickr.com/photos/zaragozaantigua/50457850423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23955, 'El Justicia Lanuza 1591', 'El Justicia Lanuza en el cadalso. Victoriano Balasanz, 1886, Ayuntamiento de Zaragoza. 20 de diciembre de 1591. El joven Justicia Juan de Lanuza se dispone a ser decapitado en la plaza del Mercado por orden de Felipe II. Al fondo, el torreâ”śâ”‚n de la Zuda.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65684100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14808150707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14808150707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14808150707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24023, 'Calle Murallas Romanas 1985', '1985. Es domingo y dâ”śÂˇa de San Blas: en el entorno donde despuâ”śÂ®s se colocarâ”śĂ­ la estatua de Câ”śÂ®sar Augusto, con la calle de las Murallas Romanas al fondo, el nâ”śâ•‘mero de la cabra. El solar tras el domador de la trompeta debajo del brazo, a la espera de ser reconstruido. A la izquierda, restos de la muralla y San Juan de los Panetes. Fuente: Colecciâ”śâ”‚n Marâ”śÂˇa Tausiet, aportada en exclusiva para el Gran Archivo Zaragoza Antigua (GAZA)', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24734691925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24734691925.webp', 'https://www.flickr.com/photos/zaragozaantigua/24734691925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24048, 'Plaza del Pilar 2002', 'El domingo 26 de noviembre de 1989, dâ”śÂˇa de Cristo Rey, un grupo de catâ”śâ”‚licos tradicionalistas se reuniâ”śâ”‚ en el Alcâ”śĂ­zar de Toledo, para conmemorar el 14 centenario del Tercer Concilio de Toledo, celebrado en 589, donde se pasâ”śâ”‚ del arrianismo al catolicismo. Estas jornadas se fueron repitiendo: al aâ”śâ–’o siguiente en El Escorial, y por fin, asentâ”śĂ­ndose en Zaragoza, entre 1992 y 2016 ininterrumpidamente. En esta ciudad contaron con el apoyo del arzobispo Manuel Ureâ”śâ–’a (2005-2014), que celebraba una misa exclusiva. Los convocantes, Junta Nacional para la Reconquista de la Unidad Catâ”śâ”‚lica, aglutinan a otras formaciones como Uniones Seglares, Misioneras Rurales, Adoraciâ”śâ”‚n Nocturna, Movimiento Catâ”śâ”‚lico Espaâ”śâ–’ol, Gerona Inmortal o Adveniat Hispania. En la foto, el grupo de las XIII Jornadas de la Unidad Catâ”śâ”‚lica, celebradas en 2002, posando ante el Pilar con algunos sâ”śÂˇmbolos fascistas. Fuente: Revista Siempre P''alante, 2002.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65698700, -0.88024000, '0101000020E61000007B319413ED2AECBFD672672618D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31098286140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31098286140.webp', 'https://www.flickr.com/photos/zaragozaantigua/31098286140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24102, 'Pl. del Justicia 1918', 'Imagen capturada en la plaza del Justicia abarrotada durante la salida de la iglesia de San Cayetano en fâ”śÂ®retro descubierto de los restos mortales del prelado de Huesca doctor Mariano Supervâ”śÂˇa Lostalâ”śÂ®, donde estuvo depositado entre el 19 y el 20 de enero de 1918 para recibir el homenaje de los feligreses de la ciudad, camino de la estaciâ”śâ”‚n ferroviaria de Campo Sepulcro para llevarle de regreso a Tauste y ser allâ”śÂˇ finalmente inhumado en la capilla de Nâ”¬Â¬. Sâ”¬Â¬. de Sancho Abarca de la iglesia de Santa Marâ”śÂˇa. La comitiva fâ”śâ•‘nebre, por disposiciâ”śâ”‚n del rey Alfonso XIII, presenta la parafernalia y honores propios de un capitâ”śĂ­n general del Ejâ”śÂ®rcito "que muere en plaza donde tiene mando como jefe". Al fondo de la escena, fachada de la iglesia de San Cayetano.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65609600, -0.88166300, '0101000020E6100000E3FBE2529536ECBFA98427F4FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51435863573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51435863573.webp', 'https://www.flickr.com/photos/zaragozaantigua/51435863573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24103, 'Calle de la Manifestaciâ”śâ”‚n 1918', 'Imagen capturada desde cierta altura del cortejo que procesionaba el fâ”śÂ®retro descubierto con los restos mortales del prelado de Huesca doctor Mariano Supervâ”śÂˇa Lostalâ”śÂ®, desde la iglesia de San Cayetano y hasta la estaciâ”śâ”‚n ferroviaria de Campo Sepulcro para llevarle de regreso a la localidad de Tauste (donde habâ”śÂˇa nacido en 1835) y ser allâ”śÂˇ finalmente inhumado en la capilla de Nâ”¬Â¬. Sâ”¬Â¬. de Sancho Abarca de la iglesia de Santa Marâ”śÂˇa. La comitiva fâ”śâ•‘nebre, que proviene de la inmediata plaza del Justicia, por disposiciâ”śâ”‚n del rey Alfonso XIII presenta la parafernalia y honores propios de un capitâ”śĂ­n general del Ejâ”śÂ®rcito "que muere en plaza donde tiene mando como jefe". Al fondo y a la izquierda, esquinero inmueble del nâ”¬â•‘ 40-46 (actual nâ”¬â•‘ 16) de la calle de la Manifestaciâ”śâ”‚n proyectado por el arquitecto Julio Bravo Folch, en cuyos bajos se ubicaban los almacenes de tejidos de la Viuda de Antonio Ferrer y Bergua.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65613600, -0.88132000, '0101000020E61000006BF12900C633ECBF37DDB243FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51453386566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51453386566.webp', 'https://www.flickr.com/photos/zaragozaantigua/51453386566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24249, 'Calle del Buen Pastor 1960', 'Imagen capturada en la puerta del Colegio Central de Santo Tomâ”śĂ­s de Aquino en su original ingreso por la calle del Buen Pastor nâ”¬â•‘ 1. Este inmueble conformaba las traseras de la antigua casa de los condes de Sobradiel, y era alquilado como parte independiente de â”śÂ®sta. Tras la clausura de una Academia de Enseâ”śâ–’anza Primaria y Secundaria aquâ”śÂˇ ubicada, Miguel Labordeta Palacios y Anselmo Gascâ”śâ”‚n de Gotor establecieron en 1920 el Colegio de Santo Tomâ”śĂ­s de Aquino, que perdurâ”śâ”‚ hasta el curso 1959-60, cuando desde la Inspecciâ”śâ”‚n de Enseâ”śâ–’anza Media se considerâ”śâ”‚ que el colegio no cumplâ”śÂˇa las exigencias mâ”śÂˇnimas para impartir clases. Cerrâ”śâ”‚, pues, en la calle del Buen Pastor para abrir en dos nuevas localizaciones: el paseo de Ruiseâ”śâ–’ores nâ”¬â•‘ 39 para el bachillerato masculino, y la calle de Gil de Jasa nâ”¬â•‘ 24 para el bachillerato femenino. De esta forma, el Colegio Notarial sito desde los aâ”śâ–’os treinta en la zona noble de la antigua casa de los Sobradiel de la plaza del Justicia, por fin consiguiâ”śâ”‚ su anhelo de expandirse, trasladando el archivo notarial y la biblioteca donde estuviera el Colegio Central de Santo Tomas de Aquino, si bien mantuvo el internado y la Enseâ”śâ–’anza Primaria. En la imagen, el co-director Manuel Labordeta Subâ”śÂˇas escenifica simbâ”śâ”‚licamente el cierre del colegio. Era director del colegio femenino abierto en 1954 en la calle de Espoz y Mina nâ”¬â•‘ 8, luego trasladado al nuevo colegio de la calle Gil de Jasa nâ”¬â•‘ 24. Tras la muerte de su hermano Miguel en 1969 y hasta 1983, aâ”śâ–’o de su propia muerte, ejerciâ”śâ”‚ de director ya en solitario. Manuel Labordeta tambiâ”śÂ®n es recordado como actor y director de cine amateur en la Zaragoza de la â”śÂ®poca. Fuente visual: "Grabado en la mente. Historia del Colegio Santo Tomaâ• ĂĽs Aquino de Zaragoza", Santiago Sancho Vallestâ”śÂˇn.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65617800, -0.88237000, '0101000020E6100000B1169F02603CECBF662D05A4FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45470432001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45470432001.webp', 'https://www.flickr.com/photos/zaragozaantigua/45470432001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24350, 'San Cayetano 1930', '"Iglesia de San Cayetano". (Iglesia de Santa Isabel de Portugal).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65584700, -0.88185100, '0101000020E6100000973C9E961F38ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852314436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852314436.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852314436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24357, 'Murallas romanas c.1954', 'Foto coloreada de una vista de las conocidas popularmente como "murallas romanas" de Zaragoza, en torno a 1955. Se trata del tramo de muralla monumentalizado entre 1946 y 1952 de la zona del torreâ”śâ”‚n de la Zuda (a la izquierda). Se distingue al fondo la pasarela peatonal sobre el Ebro, y se pueden ver las torres de San Juan de los Panetes, del Pilar (en construcciâ”śâ”‚n), la Cruz de los Caâ”śÂˇdos y la estatua de Câ”śÂ®sar Augusto. Fuente visual: J. R. Tenas.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65692600, -0.88178300, '0101000020E61000008C6665FB9037ECBF30F2B22616D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974873499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974873499.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974873499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24363, 'Pl. de Huesca 1931', 'Foto: Miguel Marâ”śÂˇn Chivite. Vista de la plaza de Huesca de Zaragoza, hoy integrada en la del Pilar. Al fondo, la torre de la iglesia de San Juan de los Panetes. El lugar era punto de encuentro de prostitutas y sus prostituidores, incluyendo las calles anexas del Fin, del Pez, de la Zuda, de los Convertidos, de las Danzas y de la Regla. Fuente: Heraldo de Aragâ”śâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65714300, -0.88064800, '0101000020E6100000B935E9B6442EECBFCDE506431DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15128603826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15128603826.webp', 'https://www.flickr.com/photos/zaragozaantigua/15128603826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24378, 'Pl. de San Cayetano 1925', 'Plaza de San Cayetano. Dibujo de Durbâ”śĂ­n. Heraldo de Aragâ”śâ”‚n, 16-4-1925. Vista de la plaza de San Cayetano (hoy del Justicia) de Zaragoza, en 1925. Al fondo, la iglesia de Santa Isabel o San Cayetano. Fuente: Eloy Fernâ”śĂ­ndez Clemente, "Gente de orden", Ibercaja, 1996.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65614300, -0.88157800, '0101000020E610000056F0DB10E335ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19662249343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19662249343.webp', 'https://www.flickr.com/photos/zaragozaantigua/19662249343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24388, 'Pl. de San Cayetano c.1920', 'Plaza de San Cayetano, luego del Justicia, con la iglesia de Santa Isabel o San Cayetano al fondo. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65619900, -0.88150300, '0101000020E6100000AD6D8AC74535ECBF7E552E54FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24289414943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24289414943.webp', 'https://www.flickr.com/photos/zaragozaantigua/24289414943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24397, 'Iglesia del Temple 1991', 'La iglesia de Santa Marâ”śÂˇa del Temple (1204) formaba parte del convento de la Orden del Temple que se estableciâ”śâ”‚ en el siglo XII en Zaragoza. Su planta era circular, siguiendo la pauta de las iglesias templarias. Su acceso estaba situado en el actual nâ”śâ•‘mero 20 de la calle del Temple, cercano a la plaza del Justicia. Durante el siglo XIX fue desamortizada, usada como almacâ”śÂ®n y finalmente derribada. En 1991 se realizaron excavaciones arqueolâ”śâ”‚gicas que desenterraron los vestigios del templo, momento que recoge la fotografâ”śÂˇa. 1. Estructura circular interior de la iglesia (edâ”śÂˇculo). 2. Sillares de muro de una vivienda romana. 3. Restos de pavimento de "opus spicatum". 4. Nivel de construcciâ”śâ”‚n de la vivienda edificada tras la reconquista de la ciudad (principios del siglo XII) y sobre la que se levantâ”śâ”‚ la iglesia. Fuente: Servicios arqueolâ”śâ”‚gicos municipales de Zaragoza, 11 de diciembre de 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65579800, -0.88147100, '0101000020E6100000D5EAABAB0235ECBF1F645930F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27605819284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27605819284.webp', 'https://www.flickr.com/photos/zaragozaantigua/27605819284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24426, 'Calle de Salduba c.1951', 'Imagen centrada en el nuevo edificio de la Tienda Econâ”śâ”‚mica y el convento de las Hijas de la Caridad de Santa Ana, proyectado en la esquinera ubicaciâ”śâ”‚n entre la nueva gran plaza del Pilar (a la izquierda) y la moderna calle de Salduba. Destacan en su fachada principal los barrocos restos del ingreso a la casa de los Salavert o Sora, ennoblecidos en el siglo XVII como marqueses de Torrecilla, originalmente en una recoleta ubicaciâ”śâ”‚n de la calle de Santo Dominguito, derribada durante el despeje para abrir la nueva calle de San Vicente de Paâ”śâ•‘l. A la izquierda y hacia el fondo destacan algunas de los inmuebles en el entorno del acceso a la calle de los Convertidos, luego derribados para dejar paso al edificio de los Juzgados y Magistratura de Trabajo de Zaragoza. Una seâ”śâ–’oras pasean, tambiâ”śÂ®n a la izquierda, junto al "Altar de la Patria" o "Monumento a los hâ”śÂ®roes y mâ”śĂ­rtires de Zaragoza. Caâ”śÂˇdos en la Cruzada de Liberaciâ”śâ”‚n 1936-1939", aâ”śâ•‘n sin terminar.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65688100, -0.88085800, '0101000020E61000006170CD1DFD2FECBF902E36AD14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49610166088.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49610166088.webp', 'https://www.flickr.com/photos/zaragozaantigua/49610166088/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20871, 'Dominguito y Albayuceto 1250', 'El niâ”śâ–’o de siete aâ”śâ–’os Dominguito de Val, infantico (monaguillo cantante) de la Seo, fue raptado por el judâ”śÂˇo Albayuceto, que lo entregâ”śâ”‚ a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Esta leyenda fue creada casi cuatro siglos despuâ”śÂ®s de los fantâ”śĂ­sticos eventos, en 1643, a imitaciâ”śâ”‚n de otras similares de marcado tono antisemita. Al fondo, la Seo. Fuente visual: Museo de Huesca, segunda mitad siglo XVII.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65359500, -0.87397400, '0101000020E6100000DCBC715298F7EBBF21EA3E00A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208834552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208834552.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208834552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24431, 'Plaza del Justicia c.1885', 'Interesante imagen de la plaza o plazuela del Justicia capturada desde la altura del nâ”¬â•‘ 27 de la calle de la Manifestaciâ”śâ”‚n. Centra la escena la fachada de la barroca Real capilla de santa Isabel, vulgo de san Cayetano. A la derecha, la calle del Buen Pastor (antigua que desde la plaza del Justicia va hasta la Subida de Botoneros), vista parcial de la Delegaciâ”śâ”‚n provincial de Hacienda ubicada donde estuviera el antiguo convento de los Teatinos de san Cayetano. A la izquierda, el inmueble del nâ”¬â•‘ 3 de la plaza, donde luce el cartelâ”śâ”‚n del nuevo comercio de ultramarinos de la Viuda de Pueyo y de Vicente Lâ”śâ”‚bez al que se entraba por el nâ”¬â•‘ 25 de la calle del Temple, mientras que por el nâ”¬â•‘ 3 se accedâ”śÂˇa al Gran Almacâ”śÂ®n de Vinos y Licores de esos mismos propietarios, que en su publicidad incluâ”śÂˇan ese aâ”śâ–’o una oportunista referencia a que "Contra el câ”śâ”‚lera: ajenjo, cognac y rom de la Jamaica". Toma ya. Por encima del inmueble emerge la Torre Nueva de la plaza de San Felipe, desmochada unos aâ”śâ–’os antes e irremediablemente encaminada a su derribo unos aâ”śâ–’os despuâ”śÂ®s. En primer tâ”śÂ®rmino destaca el adoquinado parcial de la plaza, terminado en 1875 y conducente a facilitar el ingreso a la iglesia.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65603200, -0.88189900, '0101000020E6100000DA006C408438ECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52289556348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52289556348.webp', 'https://www.flickr.com/photos/zaragozaantigua/52289556348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
